+                    try result.intervals.append(self.allocator, new_interval);
+                }
+            }
+
+            prev_upper = switch (interval.upper) {
+                .unbounded => .unbounded,
+                .included => |v| .{ .excluded = try v.clone(self.allocator) },
+                .excluded => |v| .{ .included = try v.clone(self.allocator) },
+            };
