+        for (self.intervals.items) |a| {
+            for (other.intervals.items) |b| {
+                // Compute intersection of two intervals
+                const new_lower = maxBound(a.lower, b.lower, true);
+                const new_upper = minBound(a.upper, b.upper, false);
