+                if (cmp == .lt) return a;
+                if (cmp == .eq) return b; // excluded is more restrictive
+                return b;
+            },
+        },
+        .excluded => |va| switch (b) {
+            .unbounded => a,
+            .included => |vb| {
+                const cmp = va.order(vb);
+                if (cmp == .lt or cmp == .eq) return a;
+                return b;
+            },
+            .excluded => |vb| if (va.lessThanOrEqual(vb)) a else b,
+        },
+    };
+}
