+            const propagation_result = try self.unitPropagation(next_package);
+            switch (propagation_result) {
+                .conflict => |terminal_incompat| {
+                    // No solution - build error message
+                    _ = terminal_incompat;
+                    return error.NoSolution;
+                },
+                .ok => {},
+            }
